// MEO provisioning wizard: scan -> pick a device -> Wi-Fi -> live progress -> saved.
// Rendered inside the MEO sidebar tab (tab-meo.js owns the container and view
// switching). Talks to the meo-open-service HTTP API; the step calls block, so
// live progress comes from its SSE stream (/api/v1/provision/events). SSE is
// progress sugar only — every step still resolves through the blocking call,
// so the wizard works even if the stream fails.
RED.sidebar.meo.provision = (function() {
    "use strict";

    var LAST_SSID_KEY = "meo.provision.lastSsid";

    // org.thingai.app.meo.define.ProvisionStatus values used by the checklist
    var STATUS_READING_STATUS = 8;
    var STATUS_FAILED = 11;
    var STATUS_PROVISIONED = 12;

    var opts;            // { container, getApiUrl, onClose, onProvisioned }
    var eventSource = null;
    var phase = "idle";  // idle | scan | connecting | wifi | provision | done
    var lastScan = [];   // cached scan results so "back" is instant
    var selected = null; // device picked from the scan list
    var steps = {};      // checklist step name -> element

    function t(key, params) {
        return RED._("meo.provision." + key, params);
    }

    function apiUrl(path) {
        return opts.getApiUrl() + "/api/v1/provision" + path;
    }

    function init(options) {
        opts = options;
    }

    function open() {
        openEvents();
        startScan();
    }

    function close() {
        closeEvents();
        phase = "idle";
        selected = null;
        opts.onClose();
    }

    // Devices advertise as "MEO-Setup-<name>"; children should only see <name>.
    function displayName(device) {
        var name = device && device.name ? device.name : (device ? device.address : "");
        return name.replace(/^MEO-Setup-/, "");
    }

    // ── View scaffold ──────────────────────────────────────────────

    function view(titleText, backFn) {
        var root = opts.container;
        root.empty();
        var header = $('<div class="meo-form-header"></div>').appendTo(root);
        if (backFn) {
            $('<button class="red-ui-button red-ui-button-small"><i class="fa fa-arrow-left"></i></button>')
                .attr("title", t("back"))
                .appendTo(header)
                .on("click", backFn);
        }
        $('<span class="meo-section-title"></span>').text(titleText).appendTo(header);
        return $('<div class="meo-wizard-body"></div>').appendTo(root);
    }

    // ── Step 1: scan ───────────────────────────────────────────────

    function startScan() {
        phase = "scan";
        var body = view(t("title"), close);
        $('<div class="meo-loading"><i class="fa fa-spinner fa-spin"></i> </div>')
            .append($('<span></span>').text(t("scanning")))
            .appendTo(body);
        $('<div class="meo-empty-note"></div>').text(t("scanHint")).appendTo(body);

        $.ajax({
            url: apiUrl("/scan"),
            method: "GET",
            dataType: "json",
            success: function(devices) {
                lastScan = devices || [];
                renderScanList(lastScan);
            },
            error: function() {
                renderScanError();
            }
        });
    }

    function renderScanList(devices) {
        phase = "scan";
        var body = view(t("title"), close);
        if (!devices.length) {
            $('<div class="meo-empty-note"></div>').text(t("scanEmpty")).appendTo(body);
            rescanButton(body);
            return;
        }
        var list = $('<div class="meo-list-container"></div>').appendTo(body);
        devices.forEach(function(device) {
            addDeviceRow(list, device);
        });
        rescanButton(body);
    }

    function renderScanError() {
        phase = "scan";
        var body = view(t("title"), close);
        $('<div class="meo-error"><i class="fa fa-exclamation-triangle"></i> </div>')
            .append($('<span></span>').text(t("scanError")))
            .appendTo(body);
        rescanButton(body);
    }

    function rescanButton(body) {
        $('<button class="red-ui-button meo-wizard-secondary"></button>')
            .append('<i class="fa fa-refresh"></i> ')
            .append($('<span></span>').text(t("rescan")))
            .appendTo(body)
            .on("click", startScan);
    }

    function addDeviceRow(list, device) {
        var row = $('<div class="meo-device-item"></div>').appendTo(list);
        var info = $('<div class="meo-item-info"></div>').appendTo(row);
        $('<div class="meo-item-name"></div>').text(displayName(device)).appendTo(info);
        var meta = $('<div class="meo-item-meta"></div>')
            .text(signalText(device))
            .appendTo(info);
        $('<i class="fa fa-chevron-right meo-device-go"></i>').appendTo(row);
        row.on("click", function() {
            connect(device, row, meta);
        });
    }

    function signalText(device) {
        return typeof device.rssi === "number" ? (device.rssi + " dBm") : device.address;
    }

    // ── Step 2: connect (implicit — happens when a device is tapped) ──

    function connect(device, row, meta) {
        if (phase !== "scan") {
            return;
        }
        phase = "connecting";
        row.closest(".meo-list-container").addClass("meo-list-disabled");
        row.addClass("meo-device-busy");
        meta.removeClass("meo-error-text").text(t("connecting"));

        $.ajax({
            url: apiUrl("/connect"),
            method: "POST",
            contentType: "application/json",
            data: JSON.stringify({ bleAddress: device.address }),
            success: function() {
                selected = device;
                renderWifi(null);
            },
            error: function() {
                phase = "scan";
                row.closest(".meo-list-container").removeClass("meo-list-disabled");
                row.removeClass("meo-device-busy");
                meta.addClass("meo-error-text").text(t("connectError"));
            }
        });
    }

    // ── Step 3: Wi-Fi form ─────────────────────────────────────────

    function renderWifi(errorMsg) {
        phase = "wifi";
        var body = view(t("wifiTitle", { name: displayName(selected) }), function() {
            renderScanList(lastScan);
        });
        var form = $('<div class="meo-wizard-form"></div>').appendTo(body);

        var ssidField = $('<div class="meo-wizard-field"></div>').appendTo(form);
        $('<label></label>').text(t("ssid")).appendTo(ssidField);
        var ssidInput = $('<input type="text">')
            .val(localStorage.getItem(LAST_SSID_KEY) || "")
            .appendTo(ssidField);

        var passField = $('<div class="meo-wizard-field"></div>').appendTo(form);
        $('<label></label>').text(t("password")).appendTo(passField);
        var passWrap = $('<div class="meo-wizard-password"></div>').appendTo(passField);
        var passInput = $('<input type="password">').appendTo(passWrap);
        $('<button type="button" class="red-ui-button"><i class="fa fa-eye"></i></button>')
            .attr("title", t("togglePassword"))
            .appendTo(passWrap)
            .on("click", function() {
                var hidden = passInput.attr("type") === "password";
                passInput.attr("type", hidden ? "text" : "password");
                $(this).find("i").toggleClass("fa-eye fa-eye-slash");
            });

        var errorEl = $('<div class="meo-wizard-error"></div>').appendTo(form).hide();
        if (errorMsg) {
            errorEl.text(errorMsg).show();
        }

        $('<button class="red-ui-button primary meo-wizard-submit"></button>')
            .text(t("submit"))
            .appendTo(form)
            .on("click", function() {
                var ssid = ssidInput.val().trim();
                if (!ssid) {
                    errorEl.text(t("ssidRequired")).show();
                    ssidInput.trigger("focus");
                    return;
                }
                localStorage.setItem(LAST_SSID_KEY, ssid);
                setup(ssid, passInput.val());
            });

        (ssidInput.val() ? passInput : ssidInput).trigger("focus");
    }

    // ── Step 4: setup + live checklist ─────────────────────────────

    function setup(ssid, password) {
        phase = "provision";
        renderChecklist();
        setStep("wifi", "active");

        $.ajax({
            url: apiUrl("/setup"),
            method: "POST",
            contentType: "application/json",
            data: JSON.stringify({ ssid: ssid, password: password }),
            success: function() {
                setStep("wifi", "done");
                setStep("join", "done");
                setStep("ready", "done");
                persist();
            },
            error: function() {
                // The gateway keeps the BLE session open on failure, so retrying
                // with corrected credentials needs no rescan.
                renderWifi(t("setupFailed"));
            }
        });
    }

    function renderChecklist() {
        var body = view(t("wifiTitle", { name: displayName(selected) }), null);
        var list = $('<div class="meo-wizard-steps"></div>').appendTo(body);
        steps = {};
        [["wifi", "stepWifi"], ["join", "stepJoin"], ["ready", "stepReady"]].forEach(function(step) {
            var item = $('<div class="meo-wizard-step meo-step-pending"></div>').appendTo(list);
            $('<span class="meo-step-dot"></span>').appendTo(item);
            $('<span></span>').text(t(step[1])).appendTo(item);
            steps[step[0]] = item;
        });
    }

    function setStep(name, state) {
        var item = steps[name];
        if (!item) {
            return;
        }
        item.removeClass("meo-step-pending meo-step-active meo-step-done meo-step-failed")
            .addClass("meo-step-" + state);
        var dot = item.find(".meo-step-dot").empty();
        if (state === "done") {
            $('<i class="fa fa-check"></i>').appendTo(dot);
        } else if (state === "failed") {
            $('<i class="fa fa-times"></i>').appendTo(dot);
        }
    }

    // ── Step 5: persist + done ─────────────────────────────────────

    function persist() {
        var body = opts.container.find(".meo-wizard-body");
        var saving = $('<div class="meo-loading"></div>').text(t("saving")).appendTo(body);
        $.ajax({
            url: apiUrl("/persist"),
            method: "POST",
            success: function(device) {
                if (opts.onProvisioned) {
                    opts.onProvisioned(device, displayName(selected));
                }
                renderDone();
            },
            error: function() {
                saving.removeClass("meo-loading").addClass("meo-error").text(t("saveError"));
                $('<button class="red-ui-button meo-wizard-secondary"></button>')
                    .text(t("saveRetry"))
                    .appendTo(body)
                    .on("click", function() {
                        $(this).remove();
                        saving.remove();
                        persist();
                    });
            }
        });
    }

    function renderDone() {
        phase = "done";
        var body = view(t("title"), null);
        var panel = $('<div class="meo-wizard-done"></div>').appendTo(body);
        $('<div class="meo-wizard-done-icon"><i class="fa fa-check"></i></div>').appendTo(panel);
        $('<div class="meo-wizard-done-title"></div>')
            .text(t("doneTitle", { name: displayName(selected) }))
            .appendTo(panel);
        $('<div class="meo-empty-note"></div>').text(t("doneHint")).appendTo(panel);
        $('<button class="red-ui-button primary"></button>')
            .text(t("done"))
            .appendTo(panel)
            .on("click", close);
    }

    // ── SSE progress feed ──────────────────────────────────────────

    function openEvents() {
        if (eventSource) {
            return;
        }
        try {
            eventSource = new EventSource(apiUrl("/events"));
            eventSource.addEventListener("provision.status", function(e) {
                var payload;
                try {
                    payload = JSON.parse(e.data);
                } catch (err) {
                    return;
                }
                onStatus(payload);
            });
        } catch (e) {
            eventSource = null;
        }
    }

    function closeEvents() {
        if (eventSource) {
            eventSource.close();
            eventSource = null;
        }
    }

    function onStatus(payload) {
        if (phase !== "provision" || !payload) {
            return;
        }
        var status = payload.status;
        if (status === STATUS_FAILED) {
            setStep("join", "failed");
        } else if (status === STATUS_PROVISIONED) {
            setStep("wifi", "done");
            setStep("join", "done");
            setStep("ready", "active");
        } else if (status >= STATUS_READING_STATUS) {
            setStep("wifi", "done");
            setStep("join", "active");
        }
    }

    return {
        init: init,
        open: open
    };
})();
